import http from '../http'
//产品管理


//产品

// 产品全部列表
export function ProductListAll(query: any) {
    return http.get('/jkyErp/testProduct/getList', query)
}

// 产品分页列表
export function ProductList(query: any) {
    return http.get('/jkyErp/testProduct/list', query)
}

// 产品详细
export function getProduct(id: any) {
    return http.get('/jkyErp/testProduct/' + id)
}
// 新增产品
export function addProduct(data: any) {
    return http.post('/jkyErp/testProduct/add', data)
}

// 修改产品
export function editProduct(data: any) {
    return http.post('/jkyErp/testProduct/edit', data)
}

// 删除产品
export function delProduct(teamId: number) {
    return http.post('/jkyErp/testProduct/del',teamId)
}
// 查找产品展示
export function getProductItemSel(id: any) {
    return http.get('/jkyErp/testProduct/selProduct/'+id)
}



